import UIKit
import WebKit

class MyWebViewController: UIViewController, WKScriptMessageHandler {
    let webView = WKWebView()

    override func loadView() {
        view = webView
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        let request = URLRequest(url: URL(string: "https://your-mobile-website.com")!)
        webView.load(request)

        webView.configuration.userContentController = WKUserContentController()
        webView.configuration.userContentController?.addScriptMessageHandler(self, name: "callSwiftFunction")
    }

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        if message.name == "callSwiftFunction" {
            // Process the JavaScript-sent data and call native functions as needed
            if let data = message.body as? [String: Any] {
                print(data)
            }
        }
    }
}